function redact(text = '') {
  // Keep customer email and phone visible in support logs; they are operational
  // contact details. Still redact high-risk identifiers that should not sit in
  // general workflow logs.
  return String(text).trim()
    .replace(/\b[STFGM]\d{7}[A-Z]\b/gi, '[redacted-nric-fin]')
    .replace(/\b\d{9,}\b/g, '[redacted-id]');
}

function normaliseForDedupe(text = '') {
  return redact(text).toLowerCase().replace(/\s+/g, ' ').trim();
}

function hashText(text = '') {
  let hash = 2166136261;
  for (const char of text) {
    hash ^= char.charCodeAt(0);
    hash = Math.imul(hash, 16777619);
  }
  return (hash >>> 0).toString(36);
}

function shortSession(value = '') {
  return String(value || 'session').replace(/[^a-z0-9]/gi, '').slice(0, 8) || 'session';
}

function dedupeKey(item, bucketOffset = 0) {
  const bucketSizeMs = 2 * 60 * 1000;
  const bucket = Math.floor(Date.now() / bucketSizeMs) + bucketOffset;
  const sessionId = item.session_id || item.sessionId || item.chatId || 'unknown_session';
  const messageHash = hashText(normaliseForDedupe(item.message)).toUpperCase();
  return 'SKR-DEDUP-' + shortSession(sessionId) + '-' + messageHash + '-' + bucket;
}

return items.map((item) => ({
  json: {
    ...item.json,
    user_message_redacted: redact(item.json.message),
    dedupe_key: dedupeKey(item.json),
    dedupe_key_previous: dedupeKey(item.json, -1)
  }
}));

function parseAgentOutput(value) {
  if (typeof value === 'object' && value !== null) return value;
  const text = String(value || '').trim();
  try {
    return JSON.parse(text);
  } catch (error) {
    const start = text.indexOf('{');
    const end = text.lastIndexOf('}');
    if (start >= 0 && end > start) return JSON.parse(text.slice(start, end + 1));
    throw error;
  }
}

function sgtParts(date = new Date()) {
  const shifted = new Date(date.getTime() + 8 * 60 * 60 * 1000);
  const pad = (value, length = 2) => String(value).padStart(length, '0');
  return {
    year: shifted.getUTCFullYear(),
    month: pad(shifted.getUTCMonth() + 1),
    day: pad(shifted.getUTCDate()),
    hour: pad(shifted.getUTCHours()),
    minute: pad(shifted.getUTCMinutes()),
    second: pad(shifted.getUTCSeconds()),
    ms: pad(shifted.getUTCMilliseconds(), 3),
  };
}

function sgtTimestamp(date = new Date()) {
  const parts = sgtParts(date);
  return parts.year + '-' + parts.month + '-' + parts.day + ' ' + parts.hour + ':' + parts.minute + ':' + parts.second + ' SGT';
}

function timestampForId(date = new Date()) {
  const parts = sgtParts(date);
  return '' + parts.year + parts.month + parts.day + '-' + parts.hour + parts.minute + parts.second;
}

function hashText(text = '') {
  let hash = 2166136261;
  for (const char of String(text)) {
    hash ^= char.charCodeAt(0);
    hash = Math.imul(hash, 16777619);
  }
  return (hash >>> 0).toString(36).toUpperCase();
}

function meaningful(value) {
  const text = String(value || '').trim();
  if (!text) return '';
  if (/^(n\/a|na|none|null|unknown|not_available)$/i.test(text)) return '';
  return text;
}

function firstMeaningful(...values) {
  for (const value of values) {
    const text = meaningful(value);
    if (text) return text;
  }
  return '';
}

function driveFileUrl(value = '') {
  const text = String(value || '').trim();
  if (!text) return '';
  if (/^https?:\/\//i.test(text)) return text;
  return 'https://drive.google.com/file/d/' + text + '/view';
}

function sourceUrls(values = []) {
  return values.map(driveFileUrl).filter(Boolean);
}

return items.map((item) => {
  const original = $('Restore Processing Context').first().json || {};
  const raw = item.json.output || item.json.text || item.json.response || item.json;
  let parsed;
  try {
    parsed = parseAgentOutput(raw);
  } catch (error) {
    parsed = {
      reply: 'I do not have that detail yet. I can help escalate this to the SpaceKonceptRental team.',
      intent: 'unknown',
      confidence: 0,
      needs_escalation: true,
      needs_human_followup: true,
      lead_captured: false,
      ticket_required: false,
      booking_requested: false,
      missing_fields: [],
      lead: {},
      ticket: {},
      booking: {},
      retrieval_summary: { source_titles: [], source_file_ids: [] }
    };
  }

  const now = new Date();
  const idTime = timestampForId(now);
  const referenceSuffix = hashText([original.session_id, original.message_id, original.message].join('|')).slice(0, 6);
  const ticketRequired = Boolean(parsed.ticket_required);
  const leadRequired = Boolean(parsed.lead_captured || parsed.booking_requested);
  const customerName = firstMeaningful(parsed.lead?.name, parsed.ticket?.name, original.customer_name);
  const customerEmail = firstMeaningful(parsed.lead?.email, parsed.ticket?.email, original.customer_email);
  const customerPhone = firstMeaningful(parsed.lead?.phone, parsed.ticket?.phone, original.customer_phone);
  const lead = parsed.lead || {};
  const ticket = parsed.ticket || {};

  return {
    json: {
      ...original,
      ...item.json,
      agent_raw_output: raw,
      reply: parsed.reply || 'I do not have that detail yet. I can help escalate this to the SpaceKonceptRental team.',
      intent: parsed.intent || 'unknown',
      confidence: Number(parsed.confidence || 0),
      needs_escalation: Boolean(parsed.needs_escalation),
      needs_human_followup: Boolean(parsed.needs_human_followup),
      lead_captured: Boolean(parsed.lead_captured),
      ticket_required: ticketRequired,
      booking_requested: Boolean(parsed.booking_requested),
      missing_fields: parsed.missing_fields || [],
      customer_name: customerName,
      customer_email: customerEmail,
      customer_phone: customerPhone,
      lead: {
        ...lead,
        name: firstMeaningful(lead.name, ticket.name, customerName),
        email: firstMeaningful(lead.email, ticket.email, customerEmail),
        phone: firstMeaningful(lead.phone, ticket.phone, customerPhone),
      },
      ticket: {
        ...ticket,
        name: firstMeaningful(ticket.name, lead.name, customerName),
        email: firstMeaningful(ticket.email, lead.email, customerEmail),
        phone: firstMeaningful(ticket.phone, lead.phone, customerPhone),
      },
      booking: parsed.booking || {},
      source_titles: (parsed.retrieval_summary?.source_titles || []).join(', '),
      source_file_ids: sourceUrls(parsed.retrieval_summary?.source_file_ids || []).join(', '),
      ticket_id: ticketRequired ? 'SKR-TKT-' + idTime + '-' + referenceSuffix : '',
      lead_id: leadRequired ? 'SKR-LEAD-' + idTime + '-' + referenceSuffix : '',
      escalation_reference_id: parsed.needs_escalation ? (ticketRequired ? 'SKR-TKT-' + idTime + '-' + referenceSuffix : (leadRequired ? 'SKR-LEAD-' + idTime + '-' + referenceSuffix : original.message_id)) : '',
      completed_at: sgtTimestamp(now),
      unanswered_id: 'SKR-UNANSWERED-' + idTime + '-' + referenceSuffix
    }
  };
});

const maxProcessingAgeMs = 2 * 60 * 1000;
const now = Date.now();

function parseSgtTimestamp(value) {
  const match = String(value || '').trim().match(/^(\d{4})-(\d{2})-(\d{2}) (\d{2}):(\d{2}):(\d{2}) SGT$/);
  if (!match) return NaN;
  const [, year, month, day, hour, minute, second] = match.map(Number);
  return Date.UTC(year, month - 1, day, hour - 8, minute, second);
}

function startedAt(row) {
  const value = row.created_at || row.timestamp || 0;
  const sgtParsed = parseSgtTimestamp(value);
  if (Number.isFinite(sgtParsed)) return sgtParsed;
  const parsed = Date.parse(value);
  return Number.isFinite(parsed) ? parsed : 0;
}

const active = items
  .map((item) => item.json || {})
  .filter((row) => row.status === 'processing')
  .map((row) => ({ row, startedAt: startedAt(row) }))
  .filter(({ startedAt }) => startedAt > 0 && now >= startedAt && now - startedAt < maxProcessingAgeMs)
  .sort((a, b) => b.startedAt - a.startedAt)[0];

if (!active) {
  return [{ json: { active_processing: 'false' } }];
}

return [{ json: { ...active.row, active_processing: 'true' } }];
